462	ngx_http_script_compile(ngx_http_script_compile_t *sc)
463	{
464	    u_char       ch;
465	    ngx_str_t    name;
466	    ngx_uint_t   i, bracket;
467	
468	    if (ngx_http_script_init_arrays(sc) != NGX_OK) {
469	        return NGX_ERROR;
470	    }
471	
472	    for (i = 0; i < sc->source->len; /* void */ ) {
473	
474	        name.len = 0;
475	
476	        if (sc->source->data[i] == '$') {
477	
478	            if (++i == sc->source->len) {
479	                goto invalid_variable;
480	            }
481	
482	            if (sc->source->data[i] >= '1' && sc->source->data[i] <= '9') {
483	#if (NGX_PCRE)
484	                ngx_uint_t  n;
485	
486	                n = sc->source->data[i] - '0';
487	
488	                if (sc->captures_mask & ((ngx_uint_t) 1 << n)) {
489	                    sc->dup_capture = 1;
490	                }
491	
492	                sc->captures_mask |= (ngx_uint_t) 1 << n;
493	
494	                if (ngx_http_script_add_capture_code(sc, n) != NGX_OK) {
495	                    return NGX_ERROR;
496	                }
497	
498	                i++;
499	
