501	#else
502	                ngx_conf_log_error(NGX_LOG_EMERG, sc->cf, 0,
503	                                   "using variable \"$%c\" requires "
504	                                   "PCRE library", sc->source->data[i]);
505	                return NGX_ERROR;
506	#endif
507	            }
508	
509	            if (sc->source->data[i] == '{') {
510	                bracket = 1;
511	
512	                if (++i == sc->source->len) {
513	                    goto invalid_variable;
514	                }
515	
516	                name.data = &sc->source->data[i];
517	
518	            } else {
519	                bracket = 0;
520	                name.data = &sc->source->data[i];
521	            }
522	
